// Goal at the end of the body:
//     (r1@ == ep@ && r2@ == ep@) ==> det_clone_end_point_equal(r1, r2)
// where det_clone_end_point_equal(r1, r2) := (r1.id == r2.id) on Vec<u8>.
//
// EndPoint::view is open: view(self) = AbstractEndPoint { id: self.id@ },
// and AbstractEndPoint is the single-field struct AbstractEndPoint { id: Seq<u8> },
// so EndPoint view equality decomposes structurally to Seq-level equality
// on `.id@`. The two ensures `r1@ == ep@` and `r2@ == ep@` chain
// transitively into `r1.id@ == r2.id@`. We then lift Vec<u8> structural
// equality from the Seq view by combining:
//   * `lemma_vec_obeys_view_eq::<u8>`  ⇒  obeys_view_eq::<Vec<u8>>(),
//       i.e. `x.eq_spec(&y) <==> x@ == y@`
//   * `u8_laws::lemma_obeys_concrete_eq` (in `group_laws_eq`)
//       ⇒  obeys_concrete_eq::<u8>(), the precondition above.
// Pulling both into scope and pinning Seq extensional equality gives z3
// all the facts it needs to close the postcondition without any forall
// trigger gap.

broadcast use vstd::std_specs::vec::group_vec_axioms;
broadcast use vstd::seq::group_seq_axioms;
broadcast use vstd::laws_eq::group_laws_eq;
broadcast use vstd::std_specs::vec::lemma_vec_obeys_view_eq;

assert((r1@ == ep@) && (r2@ == ep@) ==> det_clone_end_point_equal(r1, r2)) by {
    if (r1@ == ep@) && (r2@ == ep@) {
        // Decompose the AbstractEndPoint struct equality field-wise.
        assert(r1.id@ == ep.id@);
        assert(r2.id@ == ep.id@);

        // Transitivity at the Seq<u8> level.
        assert(r1.id@ == r2.id@);
        assert(r1.id@ =~= r2.id@);
        assert(r1.id@.len() == r2.id@.len());
        assert forall|i: int| 0 <= i < r1.id@.len() implies
            r1.id@[i] == r2.id@[i] by {
            assert(r1.id@[i] == ep.id@[i]);
            assert(r2.id@[i] == ep.id@[i]);
        };
    }
};
